+        let m = Hardswish;
+        let input = session
+            .tensor_variable(vec![-5.0], vec![1], false)
+            .unwrap();
+        let out = m.forward(&mut session, input).unwrap();
+        let vals = session.tensor_values(out).unwrap();
+        // hardswish(-5) = 0
+        assert!(vals[0].abs() < 1e-6);
+    }
