+    #[test]
+    fn hardsigmoid_module() {
+        let mut session = FrankenTorchSession::new(ExecutionMode::Strict);
+        let m = Hardsigmoid;
+        let input = session
+            .tensor_variable(vec![0.0, 10.0, -10.0], vec![3], false)
+            .unwrap();
+        let out = m.forward(&mut session, input).unwrap();
